 {"id":"bd-yeg2","title":"HTTP/3 server: accept and handle HTTP/3 requests","description":"# HTTP/3 Server Implementation

## Overview
HTTP/3 server implementation accepting connections over QUIC and handling
HTTP requests with Cx integration and structured concurrency.

## Design

### H3Server
```rust
pub struct H3Server {
    endpoint: QuicEndpoint,
    config: H3Config,
}

impl H3Server {
    /// Create HTTP/3 server.
    pub fn new(endpoint: QuicEndpoint, config: H3Config) -> Self {
        Self { endpoint, config }
    }

    /// Accept incoming HTTP/3 connection.
    pub async fn accept(&self, cx: &Cx) -> Outcome<H3Connection, H3Error> {
        cx.checkpoint()?;

        let quic_conn = self.endpoint.accept(cx).await?;
        let h3_conn = h3::server::Connection::new(quic_conn).await?;

        Ok(H3Connection::new(h3_conn))
    }
}
```

### H3Connection
```rust
pub struct H3Connection {
    inner: h3::server::Connection<QuicConnection, Bytes>,
}

impl H3Connection {
    /// Accept next request on this connection.
    pub async fn accept(&mut self, cx: &Cx) -> Outcome<Option<H3Request>, H3Error> {
        cx.checkpoint()?;

        match self.inner.accept().await? {
            Some((req, stream)) => {
                Ok(Some(H3Request::new(req, stream)))
            }
            None => Ok(None),  // Connection closed
        }
    }
}
```

### H3Request
```rust
pub struct H3Request {
    request: Request<()>,
    stream: h3::server::RequestStream<QuicSendStream, Bytes>,
}

impl H3Request {
    /// Get request parts.
    pub fn request(&self) -> &Request<()> {
        &self.request
    }

    /// Read request body chunk.
    pub async fn body_chunk(&mut self, cx: &Cx) -> Outcome<Option<Bytes>, H3Error>;

    /// Send response.
    pub async fn respond(
        mut self,
        cx: &Cx,
        resp: Response<impl Into<Bytes>>,
    ) -> Outcome<(), H3Error> {
        cx.checkpoint()?;

        self.stream.send_response(resp.map(|_| ())).await?;
        self.stream.send_data(resp.into_body().into()).await?;
        self.stream.finish().await?;

        Ok(())
    }

    /// Send streaming response.
    pub async fn respond_stream(
        self,
        cx: &Cx,
        resp: Response<()>,
    ) -> Outcome<H3ResponseSender, H3Error>;
}
```

