#[test]
fn stress_cancel_flood_with_ready_work() {
    init_test_logging();

    let scheduler = ThreeLaneScheduler::new(4);
    let cancel_count = Arc::new(AtomicUsize::new(0));
    let ready_count = Arc::new(AtomicUsize::new(0));
    let ready_latencies = Arc::new(Mutex::new(Vec::new()));

    // Inject cancel work that re-injects itself
    for _ in 0..100 {
        let cc = Arc::clone(&cancel_count);
        scheduler.inject_cancel(move || {
            cc.fetch_add(1, Ordering::Relaxed);
            if cc.load(Ordering::Relaxed) < 10_000 {
                // Re-inject to cancel lane
                scheduler.inject_cancel(/* same */);
            }
        });
    }

    // Inject ready work that measures latency
    for i in 0..100 {
        let start = Instant::now();
        let rc = Arc::clone(&ready_count);
        let rl = Arc::clone(&ready_latencies);
        scheduler.inject_ready(move || {
            let latency = start.elapsed();
            rl.lock().unwrap().push(latency);
            rc.fetch_add(1, Ordering::Relaxed);
        });
    }

    // Wait for all work
    scheduler.wait_idle();

    // Verify ready work completed
    assert_eq!(ready_count.load(Ordering::SeqCst), 100, "all ready work should complete");

    // Verify latency bounded
    let latencies = ready_latencies.lock().unwrap();
    let p99 = percentile(&latencies, 99);
    assert!(p99 < Duration::from_millis(100), "p99 latency {:?} too high", p99);
}

