#[test]
fn stress_cancel_flood_with_ready_work() {
    init_test_logging();

    let scheduler = ThreeLaneScheduler::new(4);
    let cancel_count = Arc::new(AtomicUsize::new(0));
    let ready_count = Arc::new(AtomicUsize::new(0));
    let ready_latencies = Arc::new(Mutex::new(Vec::new()));

    // Inject cancel work that re-injects itself
    for _ in 0..100 {
        let cc = Arc::clone(&cancel_count);
        scheduler.inject_cancel(move || {
            cc.fetch_add(1, Ordering::Relaxed);
            if cc.load(Ordering::Relaxed) < 10_000 {
                // Re-inject to cancel lane
                scheduler.inject_cancel(/* same */);
            }
        });
    }

    // Inject ready work that measures latency
    for i in 0..100 {
        let start = Instant::now();
        let rc = Arc::clone(&ready_count);
        let rl = Arc::clone(&ready_latencies);
        scheduler.inject_ready(move || {
            let latency = start.elapsed();
            rl.lock().unwrap().push(latency);
            rc.fetch_add(1, Ordering::Relaxed);
        });
    }

    // Wait for all work
    scheduler.wait_idle();

    // Verify ready work completed
    assert_eq!(ready_count.load(Ordering::SeqCst), 100, "all ready work should complete");

    // Verify latency bounded
    let latencies = ready_latencies.lock().unwrap();
    let p99 = percentile(&latencies, 99);
    assert!(p99 < Duration::from_millis(100), "p99 latency {:?} too high", p99);
}

#[test]
fn stress_cascading_cancellation() {
    // Simulate region cancellation cascade
    let scheduler = ThreeLaneScheduler::new(4);
    let ready_completed = Arc::new(AtomicBool::new(false));

    // One ready task that we want to see complete
    let rc = Arc::clone(&ready_completed);
    scheduler.inject_ready(move || {
        rc.store(true, Ordering::Release);
    });

    // Cascade: each cancel task spawns more cancel tasks
    fn inject_cascade(sched: &ThreeLaneScheduler, depth: usize) {
        if depth == 0 { return; }
        for _ in 0..3 {
            sched.inject_cancel(move || {
                inject_cascade(sched, depth - 1);
            });
        }
    }
    inject_cascade(&scheduler, 10); // 3^10 = 59049 cancel tasks

    // Ready task should complete despite cascade
    let start = Instant::now();
    while !ready_completed.load(Ordering::Acquire) {
        if start.elapsed() > Duration::from_secs(5) {
            panic!("ready work starved by cancel cascade");
        }
        std::thread::sleep(Duration::from_millis(10));
    }
}

#[test]
fn stress_lane_throughput_fairness() {
    let scheduler = ThreeLaneScheduler::new(4);
    let cancel_done = Arc::new(AtomicUsize::new(0));
    let ready_done = Arc::new(AtomicUsize::new(0));
    let timed_done = Arc::new(AtomicUsize::new(0));

    // Inject equal amounts to each lane
    for _ in 0..1000 {
        let cd = Arc::clone(&cancel_done);
        scheduler.inject_cancel(move || { cd.fetch_add(1, Ordering::Relaxed); });

        let rd = Arc::clone(&ready_done);
        scheduler.inject_ready(move || { rd.fetch_add(1, Ordering::Relaxed); });

        let td = Arc::clone(&timed_done);
        scheduler.inject_timed(move || { td.fetch_add(1, Ordering::Relaxed); }, Instant::now());
    }

    scheduler.wait_idle();

    // All lanes should complete
    assert_eq!(cancel_done.load(Ordering::SeqCst), 1000);
    assert_eq!(ready_done.load(Ordering::SeqCst), 1000);
    assert_eq!(timed_done.load(Ordering::SeqCst), 1000);
}
